132	// Restores x1..x31 and PC into the QEMU vCPU via the gdbstub at `port`,
133	// then continues. Caller is responsible for waitpid().
134	inline void restore_state_via_gdbstub(uint16_t port,
135	                                      const hybrid_state_v1& state)
136	{
137	  spdlog::info("hybrid handback: connecting to gdbstub on tcp::{}", port);
138	  const int fd = detail::connect_loopback(port, std::chrono::seconds(5));
139	  spdlog::info("hybrid handback: connected, restoring state");
140	  gdbstub::Session sess{fd};
141	
142	  for (unsigned i = 1; i < 32; ++i) {
143	    auto reply = sess.send_command(gdbstub::encode_p_body(i, state.gpr[i]));
144	    if (reply != "OK")
145	      throw std::runtime_error(
146	        "gdbstub: P packet for x" + std::to_string(i) + " replied " + reply);
147	  }
148	
149	  // RV64 GDB register layout: x0..x31 = 0..31, pc = 32.
150	  auto reply = sess.send_command(gdbstub::encode_p_body(32, state.pc));
151	  if (reply != "OK")
152	    throw std::runtime_error("gdbstub: P32 (pc) replied " + reply);
153	
154	  spdlog::info("hybrid handback: continuing target");
155	  sess.cont();
156	}
