31	// GPR ABI names as exposed by QEMU's RISC-V gdbstub; index = x register index.
32	static const char *const gpr_names[32] = {
33	    "zero", "ra",  "sp",  "gp",  "tp",  "t0", "t1", "t2",
34	    "s0",   "s1",  "a0",  "a1",  "a2",  "a3", "a4", "a5",
35	    "a6",   "a7",  "s2",  "s3",  "s4",  "s5", "s6", "s7",
36	    "s8",   "s9",  "s10", "s11", "t3",  "t4", "t5", "t6",
37	};
