39	static struct qemu_plugin_register *find_reg(GArray *regs, const char *name)
40	{
41	    for (guint i = 0; i < regs->len; i++) {
42	        qemu_plugin_reg_descriptor *rd =
43	            &g_array_index(regs, qemu_plugin_reg_descriptor, i);
44	        if (g_ascii_strcasecmp(rd->name, name) == 0) {
45	            return rd->handle;
46	        }
47	    }
48	    return NULL;
49	}
