62	static uint64_t read_reg64(struct qemu_plugin_register *h)
63	{
64	    if (!h) return 0;
65	    g_autoptr(GByteArray) buf = g_byte_array_new();
66	    int sz = qemu_plugin_read_register(h, buf);
67	    if (sz <= 0) return 0;
68	    uint64_t v = 0;
69	    memcpy(&v, buf->data, sz < 8 ? (size_t) sz : 8);
70	    return v;
71	}
