73	// Atomic on POSIX: write to .tmp, fsync, rename.
74	static int write_state_atomic(const struct hybrid_state_v1 *s, const char *path)
75	{
76	    char tmp[PATH_MAX];
77	    g_snprintf(tmp, sizeof(tmp), "%s.tmp.%d", path, (int) getpid());
78	    int fd = open(tmp, O_WRONLY | O_CREAT | O_TRUNC, 0600);
79	    if (fd < 0) {
80	        perror("hybrid_handoff: open tmp");
81	        return -1;
82	    }
83	    ssize_t want = (ssize_t) sizeof(*s);
84	    ssize_t got = write(fd, s, sizeof(*s));
85	    if (got != want) {
86	        perror("hybrid_handoff: write");
87	        close(fd);
88	        unlink(tmp);
89	        return -1;
90	    }
91	    fsync(fd);
92	    close(fd);
93	    if (rename(tmp, path) != 0) {
94	        perror("hybrid_handoff: rename");
95	        unlink(tmp);
96	        return -1;
97	    }
98	    return 0;
99	}
